// Format the error for Slack notification
const execution = $input.first().json.execution || {};
const workflow = $input.first().json.workflow || {};

const errorMessage = execution.error?.message || 'Unknown error';
const errorNode = execution.error?.node?.name || 'Unknown node';
const workflowName = workflow.name || 'Unknown workflow';
const executionId = execution.id || 'N/A';
const baseUrl = process.env.N8N_BASE_URL || 'https://timbheffins.app.n8n.cloud';

// Build Slack message
const slackMessage = {
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: ':rotating_light: Workflow Error Alert', emoji: true }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Workflow:*\n${workflowName}` },
        { type: 'mrkdwn', text: `*Failed Node:*\n${errorNode}` },
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${errorMessage.substring(0, 500)}\`\`\`` }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Execution ID:*\n${executionId}` },
        { type: 'mrkdwn', text: `*Time:*\n${new Date().toISOString()}` },
      ]
    },
    {
      type: 'actions',
      elements: [{
        type: 'button',
        text: { type: 'plain_text', text: 'View Execution' },
        url: `${baseUrl}/execution/${executionId}`,
        style: 'danger'
      }]
    }
  ]
};

return [{ json: slackMessage }];
